#!/usr/bin/env python3
"""Summarize the current fraud-evidence case file from analysis artifacts."""
from __future__ import annotations

import json
from pathlib import Path


WORKSPACE = Path(__file__).resolve().parents[1]
ANALYSIS = WORKSPACE / "analysis"

EVIDENCE_FILES = {
    "ratio_evidence": ["ж•°жҚ®е·®ејӮеҲқжӯҘеҲҶжһҗ.md", "ж•°жҚ®ж¬әиҜҲиҜҒжҚ®зҹ©йҳө.md", "зі»з»ҹжҖ§еӨёеӨ§дёҖиҮҙжҖ§еҲҶжһҗ.md"],
    "interaction_evidence": ["дә’еҠЁж•°жҚ®жҜ”зҺҮеҲҶжһҗ.md"],
    "api_inconsistency": ["еҸЈеҫ„иҫЁжһҗжҠҘе‘Ҡ.md", "еҲҳе§җи§ЈйҮҠеҸҚй©і.md"],
    "contract_noncompliance": ["е“ҒзүҢж–№жқҗж–ҷеҲҶжһҗ.md", "ж•°жҚ®жқҘжәҗеҜ№жҜ”.json"],
    "source_material_noncompliance": ["ж•°жҚ®жқҘжәҗеҜ№жҜ”.json"],
}

ADMISSION_FILES = ["жүҝи®Өи®°еҪ•еҲҶжһҗ.md"]
CONTRADICTION_FILES = ["зҹӣзӣҫжј”еҢ–ж—¶й—ҙзәҝ.md", "зҹӣзӣҫжіЁеҶҢ.json"]

KEY_EVIDENCE_LABELS = {
    "ratio_evidence": "official_vs_mcn_ratio_discrepancy",
    "interaction_evidence": "inflated_interaction_metrics",
    "api_inconsistency": "api_definition_rebuts_explanation",
    "contract_noncompliance": "verified_data_contract_breach",
    "source_material_noncompliance": "screenshots_not_api_exports",
    "admission": "liu_jie_internal_estimate_admission",
    "contradiction": "contradiction_timeline_c1_c4",
}


def exists(name: str) -> bool:
    return (ANALYSIS / name).exists()


def json_array_len(name: str) -> int:
    path = ANALYSIS / name
    if not path.exists():
        return 0
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except json.JSONDecodeError:
        return 0
    return len(data) if isinstance(data, list) else 0


def main() -> None:
    key_evidence: list[str] = []
    evidence_count = 0

    for category, files in EVIDENCE_FILES.items():
        if any(exists(file_name) for file_name in files):
            evidence_count += 1
            key_evidence.append(KEY_EVIDENCE_LABELS[category])

    admissions = sum(1 for file_name in ADMISSION_FILES if exists(file_name))
    if admissions:
        key_evidence.append(KEY_EVIDENCE_LABELS["admission"])

    contradiction_registry_count = json_array_len("зҹӣзӣҫжіЁеҶҢ.json")
    contradictions = contradiction_registry_count or sum(1 for file_name in CONTRADICTION_FILES if exists(file_name))
    if contradictions:
        key_evidence.append(KEY_EVIDENCE_LABELS["contradiction"])

    # High when the file set shows: multiple objective data discrepancies,
    # at least one admission, and a multi-node contradiction chain.
    if evidence_count >= 4 and admissions >= 1 and contradictions >= 4:
        fraud_probability = "high"
    elif evidence_count >= 3 and (admissions >= 1 or contradictions >= 2):
        fraud_probability = "medium"
    else:
        fraud_probability = "low"

    legal_action_recommended = fraud_probability == "high"

    result = {
        "evidence_count": evidence_count,
        "admissions": admissions,
        "contradictions": contradictions,
        "fraud_probability": fraud_probability,
        "legal_action_recommended": legal_action_recommended,
        "key_evidence": key_evidence,
    }
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

